1	const PROCESSING_FEE = 5;
2	
3	type Item = { type: string; cursed?: boolean; enchantment?: number };
4	type Customer = { yearsWithMHPCO: number };
5	type QuoteStep = { op: "quote"; items: Item[] };
6	type Scenario = { customer: Customer; steps: QuoteStep[] };
7	type StepResult = { premium: number };
8	type ScenarioResult = { results: StepResult[] };
9	
10	const BASE_PRICES: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const basePriceOf = (item: Item): number => BASE_PRICES[item.type] ?? 0;
20	
21	const CURSED_SURCHARGE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	
25	const isCursed = (item: Item): boolean => item.cursed === true;
26	const isHighlyEnchanted = (item: Item): boolean =>
27	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
28	
29	const surchargeRate = (item: Item): number =>
30	  (isCursed(item) ? CURSED_SURCHARGE_RATE : 0) +
31	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
32	
33	const itemSurchargeAmount = (item: Item): number =>
34	  basePriceOf(item) * surchargeRate(item);
35	
36	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
37	const BLOCK_SIZE = 3;
38	const BLOCK_PRICE = 60;
39	
40	const groupByType = (items: Item[]): Map<string, Item[]> => {
41	  const groups = new Map<string, Item[]>();
42	  for (const item of items) {
43	    const existing = groups.get(item.type) ?? [];
44	    existing.push(item);
45	    groups.set(item.type, existing);
46	  }
47	  return groups;
48	};
49	
50	const groupBasePremium = (type: string, members: Item[]): number => {
51	  if (COMPONENT_TYPES.has(type) && members.length === BLOCK_SIZE) return BLOCK_PRICE;
52	  return members.reduce((sum, item) => sum + basePriceOf(item), 0);
53	};
54	
55	const itemsBaseSubtotal = (items: Item[]): number =>
56	  Array.from(groupByType(items)).reduce(
57	    (total, [type, members]) => total + groupBasePremium(type, members),
58	    0,
59	  );
60	
61	const itemsSurchargeSubtotal = (items: Item[]): number =>
62	  items.reduce((sum, item) => sum + itemSurchargeAmount(item), 0);
63	
64	const LOYALTY_DISCOUNT_RATE = 0.2;
65	const LOYALTY_YEARS_THRESHOLD = 2;
66	
67	const isLoyalCustomer = (customer: Customer): boolean =>
68	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
69	
70	const loyaltyDiscountRate = (customer: Customer): number =>
71	  isLoyalCustomer(customer) ? LOYALTY_DISCOUNT_RATE : 0;
72	
73	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
74	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
75	
76	const hasPreviousContract = (stepIndex: number): boolean => stepIndex > 0;
77	
78	const followUpDiscountRate = (stepIndex: number): number =>
79	  hasPreviousContract(stepIndex) ? FOLLOW_UP_DISCOUNT_RATE : 0;
80	
81	const policyAdjustmentRate = (customer: Customer, stepIndex: number): number =>
82	  FIRST_INSURANCE_SURCHARGE_RATE -
83	  loyaltyDiscountRate(customer) -
84	  followUpDiscountRate(stepIndex);
85	
86	const quotePremium = (
87	  items: Item[],
88	  customer: Customer,
89	  stepIndex: number,
90	): number => {
91	  const baseSubtotal = itemsBaseSubtotal(items);
92	  const surchargeSubtotal = itemsSurchargeSubtotal(items);
93	  return (
94	    baseSubtotal +
95	    baseSubtotal * policyAdjustmentRate(customer, stepIndex) +
96	    surchargeSubtotal +
97	    PROCESSING_FEE
98	  );
99	};
100	
101	const runStep = (
102	  step: QuoteStep,
103	  customer: Customer,
104	  stepIndex: number,
105	): StepResult => ({
106	  premium: quotePremium(step.items, customer, stepIndex),
107	});
108	
109	export const runScenario = (input: Scenario): ScenarioResult => ({
110	  results: input.steps.map((step, i) => runStep(step, input.customer, i)),
111	});
